import React, { useEffect, useState } from "react";
import api from "../api";
import { motion } from "framer-motion";

export default function TodayDashboard() {
  const [todayFoods, setTodayFoods] = useState([]);

  useEffect(() => {
    const fetchDashboard = async () => {
      const res = await api.get("/foods/today");
      setTodayFoods(res.data);
    };
    fetchDashboard();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-100 to-slate-200 p-6">
      <div className=" mx-auto">
        <h1 className="text-3xl font-bold mb-8 text-center text-slate-800">Today Menu
        </h1>

        <div className="flex flex-wrap justify-center gap-6">
          {todayFoods.length === 0 && (
            <div className="text-center text-gray-500 text-lg w-full">
              No foods marked for today.
            </div>
          )}

          {todayFoods.map((food, index) => (
            <motion.div
              key={food._id}
              className="card  w-50  md:w-64 hover:shadow-2xl transition-all"
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.97 }}
            >
              {food.img && (
                <motion.img
                  src={`/uploads/${food.img}`}
                  alt={food.name}
                  className="w-full h-40 object-cover rounded-t-2xl"
                  whileHover={{ scale: 1.05 }}
                  transition={{ duration: 0.3 }}
                />
              )}

              <div className="card-body">
                <div className="font-semibold text-lg text-slate-700">
                  {food.name}
                </div>
                <div className="text-sm text-gray-500 mb-3">₹{food.price}</div>

                <motion.button
                  className="px-5 py-2 bg-green-500 text-white text-sm font-medium rounded-full shadow hover:bg-green-600"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.9 }}
                >
                  Order Now
                </motion.button>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </div>
  );
}
